// Script to generate env-config.js from environment variables
const fs = require('fs');
const path = require('path');

// Determine target directory and file
const targetFile = path.resolve(__dirname, '../public/env-config.js');

// Build the config content with environment variables
const envConfigContent = `
// This file is generated by scripts/generate-env-config.js
// It maps environment variables to window.ENV for production builds

window.ENV = {
  REACT_APP_FIREBASE_API_KEY: "${process.env.REACT_APP_FIREBASE_API_KEY || ''}",
  REACT_APP_FIREBASE_AUTH_DOMAIN: "${process.env.REACT_APP_FIREBASE_AUTH_DOMAIN || ''}",
  REACT_APP_FIREBASE_PROJECT_ID: "${process.env.REACT_APP_FIREBASE_PROJECT_ID || ''}",
  REACT_APP_FIREBASE_STORAGE_BUCKET: "${process.env.REACT_APP_FIREBASE_STORAGE_BUCKET || ''}",
  REACT_APP_FIREBASE_MESSAGING_SENDER_ID: "${process.env.REACT_APP_FIREBASE_MESSAGING_SENDER_ID || ''}",
  REACT_APP_FIREBASE_APP_ID: "${process.env.REACT_APP_FIREBASE_APP_ID || ''}",
  REACT_APP_FIREBASE_MEASUREMENT_ID: "${process.env.REACT_APP_FIREBASE_MEASUREMENT_ID || ''}",
};
`;

// Write the file
try {
  fs.writeFileSync(targetFile, envConfigContent);
  console.log(`✅ Environment configuration generated at ${targetFile}`);
} catch (error) {
  console.error(`❌ Failed to generate environment configuration: ${error.message}`);
  process.exit(1);
} 